import React, { useState } from "react";
import "./Dashboard.css";
import AddStudent from "../Student/AddStudent";

export default function Dashboard({ username = "John Doe", onLogout }) {
  const [openMenu, setOpenMenu] = useState("");
  const [activePage, setActivePage] = useState("dashboard");

  const cards = [
    { title: "Total Student", value: "20,000", color: "#f97316" },
    { title: "Teachers", value: "1,200", color: "#6366f1" },
    { title: "Staffs", value: "500", color: "#a855f7" },
    { title: "Revenue", value: "$50,000", color: "#14b8a6" },
    { title: "Expenses", value: "$12,000", color: "#22c55e" },
    { title: "Profit", value: "$38,000", color: "#0ea5e9" },
  ];

  return (
    <div className="dashboard">

      {/* Sidebar */}
      <aside className="sidebar">
        <h2 className="logo">EduDash</h2>

        <div className="profile">
          <div className="avatar">👤</div>
          <div>
            <p className="name">{username}</p>
            <span className="role">Admin</span>
          </div>
        </div>

        <ul className="menu">
          <li className="active">Dashboard</li>

          <li
            onClick={() => setOpenMenu(openMenu === "students" ? "" : "students")}
            className={`dropdown ${openMenu === "students" ? "open" : ""}`}
          >
            Students
          </li>

          {openMenu === "students" && (
            <ul className="submenu">
              <li onClick={() => setActivePage("addStudent")}>Add Student</li>
              <li>Student List</li>
            </ul>
          )}

          <li>Teachers</li>
          <li>Attendance</li>
          <li>Accounts</li>
        </ul>

        <button className="logout" onClick={onLogout}>Logout</button>
      </aside>

      {/* Main */}
      <main className="main">

        {activePage === "dashboard" && (
          <>
            {/* Topbar */}
            <div className="topbar">
              <h2>Dashboard</h2>
              <input type="text" placeholder="Search..." />
            </div>

            {/* Cards */}
            <div className="cards">
              {cards.map((card, i) => (
                <div className="card" key={i}>
                  <div
                    className="icon"
                    style={{ background: card.color }}
                  ></div>
                  <div>
                    <p>{card.title}</p>
                    <h3>{card.value}</h3>
                    <span>+10% this month</span>
                  </div>
                </div>
              ))}
            </div>

            {/* Bottom Section */}
            <div className="bottom">

              {/* Chart */}
              <div className="chart-box">
                <h3>Revenue Statistic</h3>
                <div className="chart-placeholder">
                  Chart Area
                </div>
              </div>

              {/* Attendance */}
              <div className="attendance-box">
                <h3>Student Attendance</h3>

                <div className="progress-bar">
                  <div className="present"></div>
                  <div className="absent"></div>
                  <div className="late"></div>
                  <div className="half"></div>
                </div>

                <ul>
                  <li><span className="dot green"></span> Present 87%</li>
                  <li><span className="dot orange"></span> Absent 40%</li>
                  <li><span className="dot purple"></span> Late 20%</li>
                  <li><span className="dot blue"></span> Half Day 20%</li>
                </ul>
              </div>
            </div>
          </>
        )}

        {activePage === "addStudent" && <AddStudent onBack={() => setActivePage("dashboard")} />}
      </main>
    </div>
  );
}